class Solution {
public:
    vector<int> evenOddBit(int n) {
        int even = 0, odd = 0;
        while (n) {
            even += (n & 1);
            n >>= 1;
            if (n) {
                odd += (n & 1);
                n >>= 1;
            }
        }
        return {even, odd};
    }
};
